+    fn make_simple_map() -> DoomMap {
+        use super::super::map::*;
+        // Simple square room: 4 vertices, 4 linedefs, 4 segs, 1 sector, 1 subsector
+        let vertices = vec![
+            Vertex { x: 0.0, y: 0.0 },
+            Vertex { x: 256.0, y: 0.0 },
+            Vertex { x: 256.0, y: 256.0 },
+            Vertex { x: 0.0, y: 256.0 },
+        ];
+        let sectors = vec![Sector {
+            floor_height: 0.0,
+            ceiling_height: 128.0,
+            floor_texture: "FLOOR".into(),
+            ceiling_texture: "CEIL".into(),
+            light_level: 200,
+            special: 0,
+            tag: 0,
+        }];
+        let sidedefs = vec![SideDef {
+            x_offset: 0.0,
+            y_offset: 0.0,
+            upper_texture: "-".into(),
+            lower_texture: "-".into(),
+            middle_texture: "WALL".into(),
+            sector: 0,
+        }];
+        let linedefs = vec![
+            LineDef {
+                v1: 0,
+                v2: 1,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(0),
+                back_sidedef: None,
+            },
+            LineDef {
+                v1: 1,
+                v2: 2,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(0),
+                back_sidedef: None,
+            },
+            LineDef {
+                v1: 2,
+                v2: 3,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(0),
+                back_sidedef: None,
+            },
+            LineDef {
+                v1: 3,
+                v2: 0,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(0),
+                back_sidedef: None,
+            },
+        ];
+        let segs = vec![
+            Seg {
+                v1: 0,
+                v2: 1,
+                angle: 0.0,
+                linedef: 0,
+                direction: 0,
+                offset: 0.0,
+            },
+            Seg {
+                v1: 1,
+                v2: 2,
+                angle: 0.0,
+                linedef: 1,
+                direction: 0,
+                offset: 0.0,
+            },
+            Seg {
+                v1: 2,
+                v2: 3,
+                angle: 0.0,
+                linedef: 2,
+                direction: 0,
+                offset: 0.0,
+            },
+            Seg {
+                v1: 3,
+                v2: 0,
+                angle: 0.0,
+                linedef: 3,
+                direction: 0,
+                offset: 0.0,
+            },
+        ];
+        let subsectors = vec![SubSector {
+            num_segs: 4,
+            first_seg: 0,
+        }];
+        DoomMap {
+            name: "SIMPLE".into(),
+            vertices,
+            linedefs,
+            sidedefs,
+            sectors,
+            segs,
+            subsectors,
+            nodes: vec![],
+            things: vec![],
+        }
+    }
